Article.find_or_create_by!(slug: "productivity-framework") do |a|
  a.title = "Productivity framework to focus & get more done daily at work: Goals, Context, Chunks, Distractions"
  a.excerpt = "Maximize your daily productivity at work with this comprehensive framework. By focusing on goals, context, chunks, and minimizing distractions, you’ll learn how to get more done in less time. Whether you’re struggling to stay on task or looking to take your productivity to the next level, this guide has everything you need to succeed."
  a.content = "2/ Minimise context switching\n\n– Context switching is tough. Do everything you can to minimise it in your work day\n\n– Club similar activities together so you can focus only on one area at a time eg. consolidate meeting times, schedule office hours, block time for deep focus work\n\n— Hrishikesh Pardeshi (@hrishiptweets) March 1, 2021\n\n4/ Eliminate distractions\n\nDistractions are 2 types:\n1) Ones you can control: Slack, email, social media\n2) Ones you can't control: Attending to kids/pets\n\nEliminate distractions you can control when working on a goal eg. Snoozing notifications, keeping phone away from the desk\n\n— Hrishikesh Pardeshi (@hrishiptweets) March 1, 2021\n\n5/ Use free tools & apps to keep yourself accountable\n\n– I use @NotionHQ for tracking my goals & TODOs\n\nSome other fantastic apps:\n– @todoist\n– @airtable\n– @SliteHQ\n\n— Hrishikesh Pardeshi (@hrishiptweets) March 1, 2021"
  a.category = cat
  a.published = true
  a.published_at = DateTime.parse("2023-02-27T10:16:33")
end

